export declare const AksTfExample = "\n```\nresource \"azurerm_kubernetes_cluster\" \"aks\" {\n  name                = azurecaf_name.aks.result\n  location            = azurerm_resource_group.rg.location\n  resource_group_name = azurerm_resource_group.rg.name\n  dns_prefix          = var.project_name\n  kubernetes_version  = var.kubernetes_version    // Use a stable version from `az aks get-versions --query 'values[?isDefault].version' --location <> -o tsv`\n\n  oidc_issuer_enabled       = true\n  workload_identity_enabled = true\n\n  default_node_pool {\n    name                = \"default\"\n    node_count          = 2\n    vm_size             = \"Standard_D2s_v6\"  # MUST use a vm_size from appmod-get-available-region-sku output. Do NOT hardcode.\n    os_disk_size_gb     = 30\n    vnet_subnet_id      = null\n  }\n\n  identity {\n    type         = \"SystemAssigned\"  // Use SystemAssigned identity\n  }\n\n  network_profile {\n    network_plugin    = \"kubenet\"\n    load_balancer_sku = \"standard\"\n  }\n\n  key_vault_secrets_provider {  // Add if using Key Vault\n    secret_rotation_enabled = true\n  }\n\n  tags = {\n    Environment = var.environment\n  }\n\n  depends_on = [\n  ]\n}\n\n# AcrPull role assignment for AKS identity\nresource \"azurerm_role_assignment\" \"aks_acr_pull\" {\n  principal_id                     = azurerm_kubernetes_cluster.aks.kubelet_identity[0].object_id\n  role_definition_id               = \"/subscriptions/{subscription_id}/providers/Microsoft.Authorization/roleDefinitions/7f951dda-4ed3-4680-a7ca-43fe172d538d\"\n  scope                            = azurerm_container_registry.acr.id\n  skip_service_principal_aad_check = true\n  depends_on = [ azurerm_kubernetes_cluster.aks ]  // Important\n}\n```\n";
export declare const AksKvRoleSample = "\n```\n# Key Vault Secrets User role assignment for AKS managed identity\nresource \"azurerm_role_assignment\" \"secret_user\" {\n  scope                = azurerm_key_vault.keyvault.id\n  role_definition_name = \"Key Vault Secrets User\"\n  principal_id         = azurerm_kubernetes_cluster.aks.key_vault_secrets_provider[0].secret_identity[0].object_id\n  depends_on = [ azurerm_kubernetes_cluster.aks ]\n}\n```\n";
export declare const KvCsiYamlExample = "\n1) Create a SecretProviderClass. Example:\n```\napiVersion: secrets-store.csi.x-k8s.io/v1   # MUST use x-k8s.io (this is the CRD group name registered in AKS)\nkind: SecretProviderClass\nmetadata:\n  name: azure-kvname-user-msi\nspec:\n  provider: azure\n  parameters:\n    usePodIdentity: \"false\"\n    useVMManagedIdentity: \"true\"            # Set to true for using managed identity\n    userAssignedIdentityID: ${AKS_KV_IDENTITY_CLIENT_ID}   # The clientID of the AKS Key Vault Secrets Provider identity, it can be got after AKS creation\n    keyvaultName: ${KEY_VAULT_NAME}          # The name of the Key Vault\n    objects:  |\n      array:\n        - |\n          objectName: postgres-connection-string\n          objectType: secret              # object types: secret, key, or cert\n    tenantId: ${TENANT_ID}                   # The tenant ID of the key vault\n  secretObjects:                          \n    - secretName: test-secrets-obj1       # it will create a Kubernetes secret in cluster with the name 'test-secrets-obj1'\n      type: Opaque\n      data:\n      - objectName: postgres-connection-string    # must use the same objectName as above\n        key: postgres-connection-string\n```\n2) In the deployment YAML file, mount the secret to pod. Example:\n\u26A0\uFE0F IMPORTANT: The CSI driver name in volumes.csi.driver MUST be \"secrets-store.csi.k8s.io\" (without x- prefix).\n    This is different from the SecretProviderClass apiVersion. AKS registers the CRD as x-k8s.io but the CSI driver \nas k8s.io.\n```\nkind: Pod\napiVersion: v1\nmetadata:\n  name: busybox-secrets-store-inline-user-msi\nspec:\n  containers:\n    - name: busybox\n      image: registry.k8s.io/e2e-test-images/busybox:1.29-4\n      command:\n        - \"/bin/sleep\"\n        - \"10000\"\n      env:\n      - name: SPRING_DATASOURCE_URL     # Important: set the env variable to use the secret\n        valueFrom:\n          secretKeyRef:\n            name: test-secrets-obj1    # use the secretName defined in secretObjects above\n            key: postgres-connection-string  # use the objectName defined in secretObjects above\n      volumeMounts:                    # Important: mount the volume\n      - name: secrets-store01-inline\n        mountPath: \"/mnt/secrets-store\"\n        readOnly: true\n  volumes:                            # Important: define the volume\n    - name: secrets-store01-inline  \n      csi:\n        driver: secrets-store.csi.k8s.io  # MUST use k8s.io here (NOT x-k8s.io) - this is the CSI driver\n        readOnly: true\n        volumeAttributes:\n          secretProviderClass: \"azure-kvname-user-msi\"  # Use the SecretProviderClass name defined above\n```\n";
